import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


class _AllGather(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x, world_size, rank):
        ctx.world_size = world_size
        ctx.rank = rank
        if world_size == 1:
            return x.detach().clone()
        x_contig = x.detach().contiguous()
        tensor_list = [torch.empty_like(x_contig) for _ in range(world_size)]
        dist.all_gather(tensor_list, x_contig)
        return torch.cat(tensor_list, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        if ctx.world_size == 1:
            return grad_output, None, None
        partition_size = grad_output.shape[-1] // ctx.world_size
        start = ctx.rank * partition_size
        end = (ctx.rank + 1) * partition_size
        return grad_output[..., start:end].contiguous(), None, None


class _AllReduce(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x):
        x = x.detach().clone().contiguous()
        if dist.is_initialized():
            dist.all_reduce(x, op=dist.ReduceOp.SUM)
        return x

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = dist.get_world_size()
        rank = dist.get_rank()
        partition_size = out_features // world_size
        weight_chunk = master_weight[
            rank * partition_size:(rank + 1) * partition_size, :
        ].detach().clone().contiguous()
        self.weight = nn.Parameter(weight_chunk)
        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    partition_size,
                    dtype=master_weight.dtype,
                    device=master_weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)
        self.in_features = in_features
        self.out_features = out_features

    def forward(self, x):
        output = F.linear(x, self.weight, self.bias)
        world_size = dist.get_world_size()
        rank = dist.get_rank()
        output = _AllGather.apply(output, world_size, rank)
        return output


class RowParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = dist.get_world_size()
        rank = dist.get_rank()
        partition_size = in_features // world_size
        weight_chunk = master_weight[
            :, rank * partition_size:(rank + 1) * partition_size
        ].detach().clone().contiguous()
        self.weight = nn.Parameter(weight_chunk)
        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    out_features,
                    dtype=master_weight.dtype,
                    device=master_weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)
        self.in_features = in_features
        self.out_features = out_features

    def forward(self, x):
        output = F.linear(x, self.weight, None)
        output = _AllReduce.apply(output)
        if self.bias is not None:
            output = output + self.bias
        return output
